CREATE TABLE v3_backfill_jobs(job_id UUID PRIMARY KEY,dataset_type TEXT NOT NULL CHECK(dataset_type IN ('CANONICAL','FEATURE','OUTCOME','SIMILARITY','OPPORTUNITY','CALIBRATION','VALIDATION','GOVERNANCE')),provider_code TEXT NOT NULL,scope JSONB NOT NULL,partition_start TIMESTAMP NOT NULL,partition_end TIMESTAMP NOT NULL,resolution TEXT NOT NULL,priority INTEGER NOT NULL,dependency_job_id UUID REFERENCES v3_backfill_jobs(job_id),status TEXT NOT NULL CHECK(status IN ('PENDING','RUNNING','PAUSED','RETRYING','COMPLETED','FAILED','BLOCKED')),checkpoint TEXT,attempt_count INTEGER NOT NULL DEFAULT 0,max_attempts INTEGER NOT NULL,worker_id TEXT,claimed_at TIMESTAMP,lease_expires_at TIMESTAMP,next_retry_at TIMESTAMP,terminal_failure TEXT,created_at TIMESTAMP NOT NULL,updated_at TIMESTAMP NOT NULL,CHECK(partition_end>=partition_start),CHECK(attempt_count>=0 AND max_attempts>0));
CREATE TABLE v3_backfill_attempts(attempt_id UUID PRIMARY KEY,job_id UUID NOT NULL REFERENCES v3_backfill_jobs(job_id),attempt_number INTEGER NOT NULL,state TEXT NOT NULL,previous_checkpoint TEXT,result_checkpoint TEXT,processed_count INTEGER NOT NULL CHECK(processed_count>=0),batch_checksum TEXT NOT NULL CHECK(length(batch_checksum)=64),error_type TEXT,error_message TEXT,started_at TIMESTAMP NOT NULL,completed_at TIMESTAMP,UNIQUE(job_id,attempt_number));
CREATE TABLE v3_incremental_checkpoints(checkpoint_id UUID PRIMARY KEY,job_id UUID NOT NULL REFERENCES v3_backfill_jobs(job_id),stage TEXT NOT NULL,previous_checkpoint TEXT,current_checkpoint TEXT,processed_count INTEGER NOT NULL CHECK(processed_count>=0),batch_checksum TEXT NOT NULL CHECK(length(batch_checksum)=64),state TEXT NOT NULL,created_at TIMESTAMP NOT NULL);
CREATE TABLE v3_retention_policies(policy_id UUID PRIMARY KEY,record_class TEXT NOT NULL,policy_version TEXT NOT NULL,minimum_days INTEGER,archive_eligible BOOLEAN NOT NULL DEFAULT FALSE CHECK(NOT archive_eligible),destructive_action_enabled BOOLEAN NOT NULL DEFAULT FALSE CHECK(NOT destructive_action_enabled),owner_approval_required BOOLEAN NOT NULL DEFAULT TRUE,created_at TIMESTAMP NOT NULL,UNIQUE(record_class,policy_version));
CREATE INDEX v3_backfill_claim_idx ON v3_backfill_jobs(status,next_retry_at,priority,created_at);
CREATE INDEX v3_backfill_partition_idx ON v3_backfill_jobs(dataset_type,provider_code,partition_start,partition_end);
CREATE INDEX historical_bars_scale_idx ON historical_bar_revisions(instrument_id,interval_code,bar_open_at,available_at) WHERE acceptance_state='ACCEPTED';
CREATE INDEX feature_vectors_scale_idx ON feature_vectors_v2(schema_version,instrument_id,available_at,observed_at);
CREATE INDEX outcomes_scale_idx ON historical_outcomes_v2(model_version,instrument_id,horizon_code,available_at);
CREATE INDEX similarity_candidate_scale_idx ON similarity_matches_v2(matched_vector_id,run_id);
CREATE INDEX opportunity_retrieval_scale_idx ON opportunity_candidates_v2(strategy_code,instrument_id,observed_at,state);
CREATE INDEX validation_metrics_scale_idx ON validation_metric_runs_v2(policy_version,window_end,created_at);
CREATE INDEX governance_registry_scale_idx ON research_experiments_v3(dataset_id,created_at);
CREATE INDEX continuous_claim_scale_idx ON continuous_collection_work_items(status,next_retry_at,priority,created_at) INCLUDE(provider_code,dataset_type);
CREATE FUNCTION reject_v3_scale_history_mutation() RETURNS trigger AS $$ BEGIN RAISE EXCEPTION 'V3 scale history is immutable'; END; $$ LANGUAGE plpgsql;
CREATE TRIGGER v3_backfill_attempts_immutable BEFORE UPDATE OR DELETE ON v3_backfill_attempts FOR EACH ROW EXECUTE FUNCTION reject_v3_scale_history_mutation();
CREATE TRIGGER v3_incremental_checkpoints_immutable BEFORE UPDATE OR DELETE ON v3_incremental_checkpoints FOR EACH ROW EXECUTE FUNCTION reject_v3_scale_history_mutation();
CREATE TRIGGER v3_retention_policies_immutable BEFORE UPDATE OR DELETE ON v3_retention_policies FOR EACH ROW EXECUTE FUNCTION reject_v3_scale_history_mutation();
